#pragma once

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef BLOCKDIM
#define BLOCKDIM 256
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifdef BLOCK_STRIDED
#define STRIDE_TYPE block_stride
#else
#define STRIDE_TYPE ndrange
#endif

typedef class_T data_type;

#ifdef ENABLE_HP
typedef short half2[2];
#endif

__attribute__((noinline))
data_type bench_block(data_type* data, data_type f, size_t static_chunk_size) {
  data_type sum = 0;

#ifdef BASELINE_IMPL
  data_type t = data[0];
  for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
    t = t * t + f;
  }
  sum += t;
#else
  data_type f_arr[8];
  data_type t_arr[8];

  for (int k = 0; k < 8; k++) {
    f_arr[k] = data[k];
    t_arr[k] = data[0];
  }

  for (size_t j = 0; j < COMPUTE_ITERATIONS / 8; j++) {
    for (int k = 0; k < 8; k++) {
      t_arr[k] = t_arr[k] * t_arr[k] + f_arr[k];
    }
  }

  for (int k = 0; k < COMPUTE_ITERATIONS % 8; k++) {
    t_arr[k] = t_arr[k] * t_arr[k] + f_arr[k];
  }

  for (int k = 0; k < 8; k++) {
    sum += t_arr[k];
  }
#endif

  return sum;
}

#ifdef BLOCK_STRIDED
__kernel void benchmark_func(data_type seed, __global data_type* src) {
  const size_t local_id = get_local_id(0);
  const size_t local_size = get_local_size(0);
  const size_t group_id = get_group_id(0);

  const size_t static_chunk_size = ELEMENTS_PER_THREAD;
  const size_t stride = local_size * static_chunk_size * FUSION_DEGREE;
  const size_t base_idx = group_id * stride;

  data_type sum = 0;

  for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    for (size_t chunk = 0; chunk < static_chunk_size; chunk++) {
      size_t idx = base_idx + fusion * (local_size * static_chunk_size) + 
                   local_id * static_chunk_size + chunk;

      data_type f = src[idx];
      data_type t = f;

      for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
        t = t * t + seed;
      }

      sum += t;
    }
  }

  src[base_idx + local_id * static_chunk_size] = sum;
}
#else
__kernel void benchmark_func(data_type seed, __global data_type* src) {
  const size_t global_id = get_global_id(0);
  const size_t global_size = get_global_size(0);

  const size_t static_chunk_size = ELEMENTS_PER_THREAD;
  const size_t idx = global_id * static_chunk_size * FUSION_DEGREE;

  data_type sum = 0;

  for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    for (size_t chunk = 0; chunk < static_chunk_size; chunk++) {
      size_t element_idx = idx + fusion * (static_chunk_size) + chunk;

      if (element_idx < global_size * static_chunk_size * FUSION_DEGREE / static_chunk_size) {
        data_type f = src[element_idx];
        data_type t = f;

        for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
          t = t * t + seed;
        }

        sum += t;
      }
    }
  }

  if (global_id == 0) {
    src[0] = sum;
  } else {
    src[idx] = sum;
  }
}
#endif

__kernel void benchmark_func_warmup(short seed, __global data_type* src) {
  const size_t idx = get_global_id(0);
  const size_t global_size = get_global_size(0);

  if (idx < global_size) {
    src[idx] = (data_type)seed;
  }
}
